toolArgs.old_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// Train the model at startup and register the pooled prediction engine
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var allData = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" string label to boolean
var mappedData = mlContext.Transforms.CustomMapping<CustomerData, LabelMapped>(
    (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
    contractName: null)
    .Fit(allData)
    .Transform(allData);

var split = mlContext.Data.TrainTestSplit(mappedData, testFraction: 0.2, seed: 42);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate and log metrics
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                  $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// Build a full pipeline (label mapping + trained model) for prediction
var fullPipeline = mlContext.Transforms.CustomMapping<CustomerData, LabelMapped>(
    (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
    contractName: null)
    .Append(model);
var fullModel = fullPipeline.Fit(mlContext.Data.LoadFromEnumerable(Array.Empty<CustomerData>()));

var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
mlContext.Model.Save(fullModel, allData.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with customer data");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };
    var result = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = result.PredictedLabel,
        Confidence = result.Probability
    });
});

app.Run();

public class CustomerData
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    public string Churned { get; set; } = string.Empty;
}

public class LabelMapped
{
    public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

